const CartState = {
  ACTIVE: 'active',
  CHECKOUT_STARTED: 'checkout_started',
  CHECKOUT_COMPLETE: 'checkout_complete',
  CHECKOUT_FAILED: 'checkout_failed',
  ABANDONED: 'abandoned'
};

const CartTransitions = {
  [CartState.ACTIVE]: {
    add_item: CartState.ACTIVE,
    remove_item: CartState.ACTIVE,
    update_qty: CartState.ACTIVE,
    start_checkout: CartState.CHECKOUT_STARTED,
    abandon: CartState.ABANDONED
  },
  [CartState.CHECKOUT_STARTED]: {
    cancel_checkout: CartState.ACTIVE,
    complete_checkout: CartState.CHECKOUT_COMPLETE,
    fail_checkout: CartState.CHECKOUT_FAILED,
    abandon: CartState.ABANDONED
  },
  [CartState.CHECKOUT_COMPLETE]: {},
  [CartState.CHECKOUT_FAILED]: {
    retry_checkout: CartState.CHECKOUT_STARTED,
    abandon: CartState.ABANDONED
  },
  [CartState.ABANDONED]: {
    reactivate: CartState.ACTIVE
  }
};

class ShoppingCart {
  constructor(cartId) {
    this.id = cartId;
    this.items = new Map();
    this.state = CartState.ACTIVE;
    this.createdAt = new Date();
    this.updatedAt = this.createdAt;
  }

  transition(action) {
    const allowed = CartTransitions[this.state]?.[action];
    if (!allowed) {
      throw new Error(`Invalid transition: ${this.state} -> ${action}`);
    }
    this.state = allowed;
    this.updatedAt = new Date();
  }

  addItem(product, qty = 1) {
    if (this.state !== CartState.ACTIVE) throw new Error('Cart is not active');
    const existing = this.items.get(product.id);
    if (existing) {
      existing.qty += qty;
    } else {
      this.items.set(product.id, { ...product, qty });
    }
    this.updatedAt = new Date();
  }
}

module.exports = { ShoppingCart, CartState, CartTransitions };

class APIGatewayRouter {
  constructor() {
    this.routes = new Map();
    this.globalMiddleware = [];
  }

  register(pathPrefix, serviceConfig) {
    this.routes.set(pathPrefix, {
      service: serviceConfig.service,
      host: serviceConfig.host,
      port: serviceConfig.port,
      rewrite: serviceConfig.rewrite ?? true,
      timeout: serviceConfig.timeout ?? 30000,
      retries: serviceConfig.retries ?? 2
    });
  }

  async handleRequest(req) {
    const matchedRoute = this._matchRoute(req.path);
    if (!matchedRoute) {
      return { status: 404, body: { error: 'No route found' } };
    }

    const upstreamPath = matchedRoute.rewrite
      ? req.path.replace(matchedRoute.prefix, '/')
      : req.path;

    const url = `http://${matchedRoute.host}:${matchedRoute.port}${upstreamPath}`;

    try {
      const response = await this._forwardWithRetry(url, req, matchedRoute);
      return {
        status: response.status,
        headers: response.headers,
        body: response.body
      };
    } catch (error) {
      return { status: 502, body: { error: 'Upstream service unavailable' } };
    }
  }

  _matchRoute(path) {
    let bestMatch = null;
    for (const [prefix, config] of this.routes) {
      if (path.startsWith(prefix)) {
        if (!bestMatch || prefix.length > bestMatch.prefix.length) {
          bestMatch = { prefix, ...config };
        }
      }
    }
    return bestMatch;
  }
}

module.exports = APIGatewayRouter;

const jwt = require('jsonwebtoken');
const crypto = require('crypto');

class AuthFlow {
  constructor(config) {
    this.secret = config.secret;
    this.issuer = config.issuer;
    this.tokenExpiry = config.tokenExpiry ?? '1h';
    this.refreshExpiry = config.refreshExpiry ?? '7d';
    this.tokenStore = new Map(); // token -> user data
  }

  async login(email, password) {
    const user = await this._validateCredentials(email, password);
    const accessToken = this._generateToken(user, this.tokenExpiry);
    const refreshToken = this._generateToken(
      { sub: user.id, type: 'refresh' },
      this.refreshExpiry
    );
    this.tokenStore.set(refreshToken, { userId: user.id, expiresAt: Date.now() + 7 * 86400000 });
    return { accessToken, refreshToken, expiresIn: 3600 };
  }

  async refresh(refreshToken) {
    const stored = this.tokenStore.get(refreshToken);
    if (!stored || stored.expiresAt < Date.now()) {
      throw new Error('Invalid or expired refresh token');
    }
    const user = await this._getUserById(stored.userId);
    return this.login(user.email, ''); // re-issue tokens
  }

  _generateToken(payload, expiry) {
    return jwt.sign(payload, this.secret, {
      issuer: this.issuer,
      expiresIn: expiry,
      algorithm: 'RS256'
    });
  }

  verify(token) {
    return jwt.verify(token, this.secret, { algorithms: ['RS256'], issuer: this.issuer });
  }

  logout(refreshToken) {
    this.tokenStore.delete(refreshToken);
  }
}

module.exports = AuthFlow;

class MigrationEngine {
  constructor(dbClient) {
    this.db = dbClient;
    this.migrations = new Map();
    this.appliedMigrations = new Set();
  }

  register(version, migration) {
    this.migrations.set(version, {
      version,
      up: migration.up,
      down: migration.down,
      description: migration.description
    });
  }

  async migrate(targetVersion) {
    const versions = Array.from(this.migrations.keys()).sort((a, b) => a - b);
    const toApply = versions.filter(v => v > this._getCurrentVersion());

    if (targetVersion) {
      const idx = versions.indexOf(targetVersion);
      if (idx >= 0) {
        for (let i = 0; i <= idx; i++) {
          if (versions[i] > this._getCurrentVersion()) {
            await this._applyMigration(versions[i]);
          }
        }
      }
    }
  }

  async _applyMigration(version) {
    const migration = this.migrations.get(version);
    if (!migration) throw new Error(`Migration ${version} not found`);

    console.log(`Applying migration ${version}: ${migration.description}`);
    await migration.up(this.db);
    await this._recordApplied(version);
    this.appliedMigrations.add(version);
    console.log(`Migration ${version} applied successfully`);
  }

  async _getCurrentVersion() {
    const result = await this.db.query('SELECT MAX(version) as max_ver FROM schema_migrations');
    return result?.max_ver ?? 0;
  }

  async _recordApplied(version) {
    await this.db.query(
      'INSERT INTO schema_migrations (version, applied_at) VALUES (?, ?)',
      [version, new Date().toISOString()]
    );
  }
}

module.exports = MigrationEngine;

class NotificationDispatcher {
  constructor(channels = {}) {
    this.channels = channels; // email, sms, push, webhook
    this.templateStore = new Map();
    this.deliveryLog = [];
  }

  registerTemplate(id, template) {
    this.templateStore.set(id, template);
  }

  async dispatch(userId, notification) {
    const template = this.templateStore.get(notification.templateId);
    if (!template) throw new Error(`Template ${notification.templateId} not found`);

    const userPrefs = await this._getUserPreferences(userId);
    const channels = userPrefs.channels.filter(c => notification.allowedChannels.includes(c));

    const results = [];
    for (const channel of channels) {
      try {
        const rendered = template.render(notification.variables);
        const result = await this.channels[channel].send(userId, rendered);
        results.push({ channel, status: 'sent', messageId: result.messageId });
        this.deliveryLog.push({ userId, channel, ...result, timestamp: new Date().toISOString() });
      } catch (error) {
        results.push({ channel, status: 'failed', error: error.message });
      }
    }

    return { userId, channels, results, sentCount: results.filter(r => r.status === 'sent').length };
  }

  async _getUserPreferences(userId) {
    return await this.db.query('SELECT channels, preferences FROM user_preferences WHERE user_id = ?', [userId]);
  }
}

module.exports = NotificationDispatcher;

class SearchIndexBuilder {
  constructor(searchEngine) {
    this.engine = searchEngine;
    this.index = new Map();
    this.pendingChanges = [];
    this.batchSize = 100;
    this.flushTimer = null;
  }

  indexDocument(doc) {
    const entry = {
      id: doc.id,
      content: this._tokenize(doc.content),
      metadata: { title: doc.title, category: doc.category, updatedAt: new Date().toISOString() },
      score: 1.0
    };
    this.index.set(doc.id, entry);
    this.pendingChanges.push({ type: 'index', doc: entry });
    this._scheduleFlush();
  }

  updateDocument(docId, updates) {
    const existing = this.index.get(docId);
    if (!existing) {
      this.indexDocument(updates);
      return;
    }
    Object.assign(existing.metadata, updates);
    existing.content = this._tokenize(updates.content ?? existing.metadata.title);
    this.pendingChanges.push({ type: 'update', docId, doc: existing });
    this._scheduleFlush();
  }

  deleteDocument(docId) {
    this.index.delete(docId);
    this.pendingChanges.push({ type: 'delete', docId });
    this._scheduleFlush();
  }

  async flush() {
    if (this.pendingChanges.length === 0) return;

    const batch = this.pendingChanges.splice(0, this.batchSize);
    const indexed = batch.filter(c => c.type === 'index').map(c => c.doc);
    const updated = batch.filter(c => c.type === 'update').map(c => c.doc);
    const deleted = batch.filter(c => c.type === 'delete').map(c => c.docId);

    await this.engine.bulkUpdate({ indexed, updated, deleted });
    this._scheduleFlush();
  }

  _scheduleFlush() {
    if (this.flushTimer) clearTimeout(this.flushTimer);
    this.flushTimer = setTimeout(() => this.flush(), 1000);
  }

  _tokenize(text) {
    return text.toLowerCase().split(/\s+/).filter(t => t.length > 0);
  }
}

module.exports = SearchIndexBuilder;

const OrderStatus = {
  PENDING: 'pending',
  CONFIRMED: 'confirmed',
  PROCESSING: 'processing',
  SHIPPED: 'shipped',
  DELIVERED: 'delivered',
  COMPLETED: 'completed',
  CANCELLED: 'cancelled'
};

const FULFILLMENT_STEPS = [
  { from: OrderStatus.PENDING, to: OrderStatus.CONFIRMED, action: 'confirm', handler: confirmOrder },
  { from: OrderStatus.CONFIRMED, to: OrderStatus.PROCESSING, action: 'process', handler: processOrder },
  { from: OrderStatus.PROCESSING, to: OrderStatus.SHIPPED, action: 'ship', handler: shipOrder },
  { from: OrderStatus.SHIPPED, to: OrderStatus.DELIVERED, action: 'deliver', handler: deliverOrder },
  { from: OrderStatus.DELIVERED, to: OrderStatus.COMPLETED, action: 'complete', handler: completeOrder }
];

class OrderPipeline {
  constructor(order) {
    this.order = order;
    this.currentStep = 0;
    this.history = [{ status: order.status, timestamp: new Date() }];
  }

  canAdvance(action) {
    const step = FULFILLMENT_STEPS[this.currentStep];
    return step && step.action === action;
  }

  async advance(action) {
    if (!this.canAdvance(action)) {
      throw new Error(`Cannot perform '${action}' in status ${this.order.status}`);
    }

    const step = FULFILLMENT_STEPS[this.currentStep];
    await step.handler(this.order);
    this.order.status = step.to;
    this.currentStep++;
    this.history.push({ status: step.to, action, timestamp: new Date() });
  }

  cancel() {
    this.order.status = OrderStatus.CANCELLED;
    this.history.push({ status: OrderStatus.CANCELLED, action: 'cancel', timestamp: new Date() });
  }

  getTimeline() { return [...this.history]; }
}

module.exports = { OrderPipeline, OrderStatus, FULFILLMENT_STEPS };

class AnalyticsEventPipeline {
  constructor(options = {}) {
    this.processors = [];
    this.buffer = [];
    this.bufferSize = options.bufferSize ?? 100;
    this.flushInterval = options.flushInterval ?? 5000;
    this.schemaValidators = new Map();
    this.metrics = { received: 0, processed: 0, dropped: 0 };
    this._flushTimer = setInterval(() => this._flushBuffer(), this.flushInterval);
  }

  registerProcessor(name, processor, schema) {
    this.processors.push({ name, processor });
    if (schema) this.schemaValidators.set(name, schema);
  }

  async processEvent(event) {
    this.metrics.received++;

    // Validate against registered schemas
    for (const [name, schema] of this.schemaValidators) {
      if (!schema.validate(event)) {
        this.metrics.dropped++;
        return;
      }
    }

    this.buffer.push({ ...event, processedAt: new Date().toISOString() });

    if (this.buffer.length >= this.bufferSize) {
      await this._flushBuffer();
    }
  }

  async _flushBuffer() {
    if (this.buffer.length === 0) return;
    const batch = this.buffer.splice(0, this.bufferSize);

    for (const processor of this.processors) {
      try {
        await processor.processor(batch);
        this.metrics.processed += batch.length;
      } catch (err) {
        console.error(`Processor ${processor.name} failed:`, err.message);
        this.metrics.dropped += batch.length;
      }
    }
  }

  shutdown() {
    clearInterval(this._flushTimer);
    return this._flushBuffer();
  }
}

module.exports = AnalyticsEventPipeline;
